using System.Reflection;

var dllPath = "/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net10.0/Microsoft.Agents.AI.dll";
var asm = Assembly.LoadFrom(dllPath);

// Also load abstractions
var absPath = Directory.GetFiles("/home/runner/.nuget/packages/microsoft.agents.ai.abstractions", "*.dll", SearchOption.AllDirectories)
    .FirstOrDefault(f => f.Contains("net10.0") || f.Contains("net9.0") || f.Contains("net8.0"));
if (absPath != null) {
    var absAsm = Assembly.LoadFrom(absPath);
    PrintAssembly(absAsm, "Abstractions");
}

PrintAssembly(asm, "AI");

static void PrintAssembly(Assembly asm, string label)
{
    Console.WriteLine($"\n=== {label} ===");
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
    {
        var baseType = t.BaseType?.Name != "Object" ? $" : {t.BaseType?.Name}" : "";
        var ifaces = t.GetInterfaces().Where(i => i.IsPublic).Select(i => i.Name);
        Console.WriteLine($"\n{(t.IsInterface ? "interface" : t.IsAbstract ? "abstract class" : t.IsEnum ? "enum" : "class")} {t.FullName}{baseType}");

        // Constructors
        foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
            Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");

        // Properties
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"  {p.PropertyType.Name} {p.Name} {{ {(p.CanRead?"get;":"")}{(p.CanWrite?" set;":"")} }}");

        // Methods (skip property accessors)
        var propNames = t.GetProperties().SelectMany(p => new[] { $"get_{p.Name}", $"set_{p.Name}" }).ToHashSet();
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
            .Where(m => !propNames.Contains(m.Name) && !m.IsSpecialName))
        {
            var ret = m.ReturnType.Name;
            Console.WriteLine($"  {ret} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        }
    }
}
EOF
