    <PackageReference Include="Microsoft.Extensions.AI" Version="9.*" />
  </ItemGroup>
</Project>
EOF
cat > Program.cs << 'CSEOF'
using System.Reflection;

var packages = new[] {
    ("Microsoft.Agents.AI.Abstractions", "net10.0"),
    ("Microsoft.Agents.AI", "net10.0"),
};

foreach (var (pkg, tfm) in packages)
{
    var dir = Directory.GetDirectories($"/home/runner/.nuget/packages/{pkg.ToLower()}")
        .OrderDescending().FirstOrDefault();
    if (dir == null) continue;
    var dll = Path.Combine(dir, "lib", tfm, $"{pkg}.dll");
    if (!File.Exists(dll)) { dll = Path.Combine(dir, "lib", "net9.0", $"{pkg}.dll"); }
    if (!File.Exists(dll)) continue;

    var asm = Assembly.LoadFrom(dll);
    Console.WriteLine($"\n=== {pkg} ===");
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
    {
        var kind = t.IsInterface ? "interface" : t.IsAbstract ? "abstract" : t.IsEnum ? "enum" : "class";
        var bt = t.BaseType != null && t.BaseType != typeof(object) ? $" : {t.BaseType.Name}" : "";
        Console.WriteLine($"\n  {kind} {t.Name}{bt}");
        foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
            Console.WriteLine($"    ctor({string.Join(", ", c.GetParameters().Select(p => $"{SimpleName(p.ParameterType)} {p.Name}"))})");
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"    {SimpleName(p.PropertyType)} {p.Name} {{ {(p.CanRead?"get;":"")}{(p.CanWrite?" set;":"")} }}");
        var propNames = t.GetProperties().SelectMany(p => new[] { $"get_{p.Name}", $"set_{p.Name}" }).ToHashSet();
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly | BindingFlags.Static)
            .Where(m => !propNames.Contains(m.Name) && !m.IsSpecialName))
        {
            var stat = m.IsStatic ? "static " : "";
            Console.WriteLine($"    {stat}{SimpleName(m.ReturnType)} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{SimpleName(p.ParameterType)} {p.Name}"))})");
        }
    }
}

static string SimpleName(Type t) {
    if (t.IsGenericType) {
        var name = t.Name.Split('`')[0];
        return $"{name}<{string.Join(",", t.GetGenericArguments().Select(SimpleName))}>";
    }
    return t.Name;
}
CSEOF
