using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities using DuckDuckGo's HTML endpoint (no API key required).
/// </summary>
public sealed class WebSearchTool : IDisposable
{
    private readonly HttpClient _httpClient;

    public WebSearchTool()
    {
        _httpClient = new HttpClient();
        _httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
        _httpClient.Timeout = TimeSpan.FromSeconds(15);
    }

    [Description("Search the web for information on a given query. Returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(query);

        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        string html;
        try
        {
            html = await _httpClient.GetStringAsync(url, cancellationToken);
        }
        catch (HttpRequestException ex)
        {
            return $"[Search error: {ex.Message}]";
        }

        var results = ParseSearchResults(html);

        if (results.Count == 0)
            return $"No results found for: {query}";

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for: {query}");
        sb.AppendLine();

        foreach (var (title, link, snippet) in results)
        {
            sb.AppendLine($"**{title}**");
            sb.AppendLine($"  URL: {link}");
            sb.AppendLine($"  {snippet}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private static List<(string Title, string Url, string Snippet)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        // Match DuckDuckGo result blocks
        var resultPattern = ResultBlockRegex();
        var matches = resultPattern.Matches(html);

        foreach (Match match in matches)
        {
            if (results.Count >= 5)
                break;

            var linkHtml = match.Value;

            var titleMatch = TitleRegex().Match(linkHtml);
            var snippetMatch = SnippetRegex().Match(linkHtml);

            var title = titleMatch.Success ? StripHtml(WebUtility.HtmlDecode(titleMatch.Groups[1].Value)).Trim() : "";
            var snippet = snippetMatch.Success ? StripHtml(WebUtility.HtmlDecode(snippetMatch.Groups[1].Value)).Trim() : "";

            // Extract the actual URL from DuckDuckGo's redirect
            var hrefMatch = HrefRegex().Match(linkHtml);
            var rawUrl = hrefMatch.Success ? WebUtility.HtmlDecode(hrefMatch.Groups[1].Value) : "";
            var actualUrl = ExtractActualUrl(rawUrl);

            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(actualUrl))
                results.Add((title, actualUrl, snippet));
        }

        return results;
    }

    private static string ExtractActualUrl(string ddgUrl)
    {
        // DuckDuckGo wraps URLs like //duckduckgo.com/l/?uddg=https%3A%2F%2F...&rut=...
        var uddgMatch = UddgRegex().Match(ddgUrl);
        if (uddgMatch.Success)
            return Uri.UnescapeDataString(uddgMatch.Groups[1].Value);

        if (ddgUrl.StartsWith("http", StringComparison.OrdinalIgnoreCase))
            return ddgUrl;

        return ddgUrl;
    }

    private static string StripHtml(string html) =>
        HtmlTagRegex().Replace(html, "").Trim();

    public void Dispose() => _httpClient.Dispose();

    [GeneratedRegex(@"<div class=""result results_links[\s\S]*?</div>\s*</div>\s*</div>", RegexOptions.IgnoreCase)]
    private static partial Regex ResultBlockRegex();

    [GeneratedRegex(@"class=""result__a""[^>]*>([\s\S]*?)</a>", RegexOptions.IgnoreCase)]
    private static partial Regex TitleRegex();

    [GeneratedRegex(@"class=""result__snippet""[^>]*>([\s\S]*?)</[at]", RegexOptions.IgnoreCase)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex(@"class=""result__a""\s+href=""([^""]+)""", RegexOptions.IgnoreCase)]
    private static partial Regex HrefRegex();

    [GeneratedRegex(@"uddg=([^&]+)")]
    private static partial Regex UddgRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex HtmlTagRegex();
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    [Description("Save a research note with a title and content. Use this to record important findings from your research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        ArgumentException.ThrowIfNullOrWhiteSpace(content);

        _notes.Add((title, content, DateTime.UtcNow));
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieve all saved research notes. Use this to review your collected findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        sb.AppendLine();

        for (var i = 0; i < _notes.Count; i++)
        {
            var (title, content, timestamp) = _notes[i];
            sb.AppendLine($"[{i + 1}] {title}");
            sb.AppendLine($"    Saved at: {timestamp:u}");
            sb.AppendLine($"    {content}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

