using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build tools ---
using var webSearch = new WebSearchTool();
var noteTaking = new NoteTakingTool();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(noteTaking.SaveNote),
    AIFunctionFactory.Create(noteTaking.GetNotes),
};

// --- Build the chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and organizing findings into notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    });

var instructions = """
    You are a research assistant. Your job is to thoroughly research a topic 
    provided by the user and produce a well-organized summary.

    Follow this workflow:
    1. Break the topic into 2-3 specific search queries.
    2. Use the SearchAsync tool to search the web for each query.
    3. Use the SaveNote tool to save the most important findings from each search.
    4. Use the GetNotes tool to review all your collected notes.
    5. Synthesize your notes into a clear, well-structured summary with key points and sources.

    Always cite the sources (URLs) where you found the information.
    Be thorough but concise — aim for a summary that covers the key aspects of the topic.
    """;

// --- Main loop ---
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔍 AI Research Agent              ║");
Console.WriteLine("║  Enter a topic to research, or 'quit'.   ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic> ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic))
        continue;

    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase) ||
        topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine(new string('─', 50));

    try
    {
        // Create a new session per research topic
        var session = await agent.CreateSessionAsync();

        // Seed the session with instructions and the user's topic
        var messages = new ChatMessage[]
        {
            new(ChatRole.System, instructions),
            new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary:\n\n{topic}"),
        };

        // Stream the agent's response
        await foreach (var update in agent.RunStreamingAsync(messages, session))
        {
            if (!string.IsNullOrEmpty(update.Text))
                Console.Write(update.Text);
        }

        Console.WriteLine();
        Console.WriteLine(new string('─', 50));
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\n[Error] {ex.Message}");
    }

    Console.WriteLine();
}

